insert into exercises (id, name, video_url, technique_notes, muscle_group) values
  ('39b601aa-3273-45d6-be0a-5681f5a13c2b', 'BRACING', 'https://youtube.com/shorts/vWRgGszXRpE', 'respiracion disfragmatica (solo por abdomen) para aplicarla en el resto de los ejercicios y mantener una estabilidad central q nos proteja la columna', null),
  ('43a0ab01-28b7-4c31-b43c-ddbcf3ad0c41', 'GOBLET SQUAT BENCH', 'GOBLET SQ TO BENCH.mp4', 'rodillas afuera (no pies). toco banco y subo/ tomo aire arriba. mantengo al bajar y suelto al subir', null),
  ('4ba8afec-0f9c-4c50-825e-6bd39be4a065', 'PESO MUERTO RUMANO CON MANCUERNAS', 'DL con DB.mp4', 'rodillas hacia afuera. pies completos apoyados TODO el recorrido. al llegar abajo de la rodilla con MANCUERNAS subo. PESO PEGADO AL CUERPO tomo aire abajo mantengo al subir y suelto al bajar.', null),
  ('5b58cec4-e2f5-432b-af66-fbf4847f1a06', 'molino con aductor', 'windmill mobility .mp4', 'separo rodillas lo mas posible. mantengo neutralidad en columna (no exagerar meter o sacar cola). mano en nuca, el codo busca antebrazo contrario y busco rotar lo mas posible. EVITO ELEVAR HOMBROS', null),
  ('f4c5fbf3-7e00-494f-bbb7-3c80a1d54b6a', 'REMO TRX', 'IMG_3133.MOV', 'saco pecho todo el tiempo. cuerpo como una plancha. cadera y hombros se mueven juntos. tomo aire atras. mantengo al subir y suelto al bajar', null),
  ('5fe6baba-9a9f-4bf4-bd28-6eca657b6f3c', 'TEMPO PUSH UP EN BANCO', 'PUSH UP BENCH.mp4', 'CUENTO 3 SEGUNDOS PARA BAJAR, MANTENGO 2 Y SUBO EN UN SEGUNDO. tomo aire arriba. mantengo al bajar y suelto al subir. hombro y cadera se mueven juntos/ codos a 45 grados.', null),
  ('8b5ad0de-8954-467c-be06-8c15e539e189', 'jefferson', 'JEFFERSON.mp4', 'me plego como un gusano segmentando la columna, primero cervical, despues dorsal, despues lumbar y ultimo sacro. RODILLAS EXTENDIDAS PESO DISTRIBUIDO EN TODA PLANTA DEL PIE,. vuelvo igual al revez lo ultimo q sube es la cabeza', null),
  ('e052c496-0d5d-4e15-af04-1b1db016bb19', 'TRIPLE AMENAZA', 'IMG_2499.MOV', 'cola arriba todo el tiempo. brazos apoyados. tomo aire piernas extendidas. mantengo al traccionar y suelto al extender.', null),
  ('994390a8-9aab-4abd-b181-b1c7167baf96', 'SENTADILLA SPLIT', 'SPLIT SQ DB.mp4', 'tomo aire arriba, mantengo al bajar y suelto al subirparada me dejo caer para establecer distancia. al bajar, rodilla de adelante hacia afuera y deberia quedar en angulo de 90 grados. extiendo completamente al subir', null),
  ('86db86c7-a07c-4fd0-b3c4-0a4d3bdf69df', 'TOBILLO', 'ANKLE W KB.mp4', 'Tiro rodilla lo mas adelante posible, no el cuerpo. solo rodilla. sin levantar talon.', null),
  ('778dbfb5-e221-4b00-b573-3b92396b7e7c', 'PRESS MILITAR', 'PRESS MILITAR DB D.mp4', 'palmas enfrentadas todo el tiempo. no balanceo cuerpo, subo brazos hasta que queden al costado de la oreja. tomo aire mientras subo suelto al bajar', null),
  ('b62c5937-5ae8-443d-b325-b16e10810c6f', 'REMO UNILAT POLEA', 's row pulley(1).mp4', 'cadera y hombros derechos mirando a la polea. codo pegado al cuerpo. pie contrario adelantado para mas estabilidad. tomo aire. tracciono manteniendo y suelto al volver el brazo', null),
  ('e7c46ac4-ef80-4e21-883f-49262340dc67', 'COLGARSE', 'Hang.mp4', 'Agarre completo de la mano sobre la barra/ me dejo colgar y suelto todo el cuerpo', null),
  ('70ec927f-4203-4c14-b77b-fca8d0d5213e', 'SALTO UNIPODAL A BASE', 'SINGLE HOP TO STEP.mp4', 'MANOS EN CINTURA. salto y al estabilizar vuelvo a saltar para atras. tratar de controlar que rodilla no se vaya adentro, siempre afuera', null),
  ('2003ffec-eea5-4b2a-b6c1-b75c3d1a2865', 'PALLOF PRESS', 'PALLOF PRESS(1).mp4', 'APLICO BRACING. mentengo aire adelante unos 2 a 3 seg y vuelvo. hombro y cadera miran hacia adelante', null),
  ('e6a1d101-0be3-4fd1-af0c-baf86686d15f', 'goblet sq con peso y cajon/step', 'SQUAT TO STEP SUB.mp4', 'Talones pegados al step. rodillas afuera. peso distribuido en toda la planta del pie', null),
  ('3efed87a-b66f-42f2-80d2-77dc640057ef', 'GLUTEO MEDIO CON BANDA PARADA', 'medium glute stand band.mp4', 'mantengo apertura 3 segundos. rodillas rotacion externa. evito abrir la cadera. semiflexion de rodilla.', null),
  ('7b36b15b-5b7b-41cd-a226-6e8692607cdf', 'PESO MUERTO CABRA', 'DL TOMA CABRA SUB.mp4', 'marco bisagra de cadera. la cadera por atras de la linea de la rodilla y del pie. rodillas hacia afuera', null),
  ('813b8f52-99dd-49ec-bc6a-d3cc16aa76e5', 'glute bridge', 'GLUTE BRIDGE SUB.mp4', 'Cadera alineada. tomo aire abajo. mantengo mientras subo y suelto al bajar.', null),
  ('407479a7-36b0-4035-95d9-47abf674fd60', 'plancha APLICANDO BRACING', 'floor plank sub.mp4', 'alineo hombro y cadera. aplico bracing. suelto el aire ajustando el abdomen.', null),
  ('1c9a01b5-9e03-41f5-a75f-f9d1fa00d1d4', 'CARPA', 'carpa.mp4', 'posicion de plancha, subo cadera y busco meter cabeza lo mas adentro posible, sacar cola y buscar talon al suelo. no despego apoyo de pies o manos NUNCA', null),
  ('2f072f6b-8ccf-4eee-887c-84fcaeed11bb', 'SENTADILLA RACK', 'RACK SQ(1).mp4', 'con supercificie en talones. . bajo lo mas posible siempre y cuando todo el pie este apoyado en todo momento y torso no se vaya adelante. tomo aire arriba mantengo al bajar y suelto al subir. bajo controlado y subo lo mas rapido posible', null),
  ('0f2040f2-173c-4954-8f87-41a24de3eb96', 'PESO MUERTO RUMANO CON BARRA', 'RDL SUB.mp4', 'rodillas hacia afuera. pies completos apoyados TODO el recorrido. al llegar abajo de la rodilla con barra subo', null),
  ('5b2607eb-9b21-4a8e-8ae3-5679b2d85a2a', 'W A Y POSICION SUPINA', 'W TO Y laydown.mp4', 'junto escapulas al marcar w y trato de no pegar hombros a oreja cuando extiendo los codos a Y', null),
  ('8dbbf3e8-4d52-42f7-8cda-99ac96c8c33b', 'chin ups', 'CHIN UPS .mp4', 'palmas miran HACIA VOS. AL BAJAR, extiendo los codos por completo,', null),
  ('4dd27aa3-26d6-4d47-ae22-04f5ee752b10', 'PUSH UP BANCO', 'PUSH UP BENCH.mp4', 'hombro y cadera se mueven juntos. aplico bracing. mantengo respiracion mientras bajo y suelto al subir ajustando abdomen. bajo de manera controlada y subo rapido MIENTRAS MAS BAJO EL BANCO MAS DIFICIL.', null),
  ('98ec8950-19a9-42e5-818b-7120d5acd8f2', 'open book', 'open book wall .mp4', 'trato de no tocar la pared.junto escapulas en maxima apertura. evito levantar los hombros (pegarlos a la cabeza) sigo con la mirada el movimiento', null),
  ('4756fede-e1ae-46f6-b248-8885d8f78786', 'DL unilateral', '1SIDE DEADLIFT.mp4', 'TODO PESO en pie de ADELANTE. mismo movimiento que peso muerto, tiro cadera hacia atras, espalda derecha.', null),
  ('9631c9cf-c253-47da-bb1c-1b1aa8a2d31e', 'PISTOL TRX', 'pistol squat .mp4', 'trx solo ayuda para estabilidad, fuerza de pierna para subir empujando el suelo (NO HAGO FUERZA CON BRAZOS)', null),
  ('d678b8ea-a998-4b33-b2cb-bb12678914b0', 'SPIDERMAN APOYO Y DESAPOYO RODILLA.', 'spiderman .mp4', 'Pie a la altura de la mano. esaplda derecha. rodilla de atras se flexiona y se extiende  por completo.', null),
  ('9f215909-1ca1-47ba-a481-aff1b6c66714', 'DB PRESS INCLINADO', 'DB INCLINE BENCH PRESS.mp4', 'codos a 45 grados. al subir las manos quedan alineadas con codos y hombros.', null),
  ('a85f1276-1c77-4481-af6d-1fb22d57b3ae', 'SEAL ROW', 'SEAL ROW.mp4', 'no levanto pecho. subo rapido y bajo controlado. tomo aire cuando subo.suelto al bajar.  La fuerza es en la espalda', null),
  ('8a6bcaea-de5f-46a2-9543-eb06fbc785c4', 'AJUSTE COLGADO', 'Scapular adjustment.mp4', 'codos NO se flexionan nunca. es hacer un movimiento de "que me importa" con los hombros ascendiendo y descendiendo los mismos.', null),
  ('4effccf7-9a9a-45ef-bc05-46a11f279873', 'LIFT', 'LIFT SPLIT MB.mp4', 'el movimiento es diagonal y comienza desde el lado de la pierna atrasada. el movimiento es EXPLOSIVO COMO SI FUESES A revolear la pelota. tomo aire abajo y suelto al subir. lo principal del movimiento es NO ROTAR la columna y frenar la propulsion del movimiento.', null),
  ('a5a8d655-e975-4ece-a497-e488931e614f', 'PLANCHA EN FITBALL', 'FITBAL PLANK.mp4', 'rechazo la pelota, codos a altura de hombro y mantengo posicion ajustando el abdomen para que la cadera no caiga. APLICO BRACING. mientras mas juntos los pies mas dificil', null),
  ('ff34e608-0ff5-4290-966c-47c38c3550c0', 'SALTO VERTICAL', 'vertical jump.mp4', 'posicion inicial: rodillas semiflexionadas y rotadas hacia afuera.  salto lo MAS ALTO posible llevando brazos arriba aprovechando el impulso y busco extenderme por completo, al caer: estabilizo y amortiguo sin hacer ruido. UNA VEZ Q ENCONTRE EQUILIBRIO Y CONTROLE EL MOVIMIENTO SALGO DE VUELTA', null),
  ('86624d8a-7e40-4609-a6f6-4b2c94e34d17', 'gluteo medio polea', 'Gluteo medio en polea (abductor) - YouTube', 'pierna del suelo por delante del cable. no compensar con el torso inclinandolo, siempre bien derecho. mantengo el aire al subir pierna y suelto al bajar tratando de controlar el movimiento y que no te gane la fuerza de la polea', null),
  ('7ba8e37f-b1f0-4ec9-a0af-1b480f7e3d13', 'hop lateral a step', 'lateral hop.mp4', 'brazos a la cintura. estabilizo y luego salto de vuelta. salto hacia afuera y hacia adentro y se cuenta como una.', null),
  ('207974bd-2090-43a0-9edf-7f609c2f33c0', 'split p/ tobillo', 'SPLIT SQUAT TO ANKLE .mp4', 'trato de llevar la rodilla de adelante lo mas adelante posible sin que se levante el talon. espalda derecha. puede hacerse con un peso en cada mano o solo uno. no importa el lado', null),
  ('05b970ca-84bf-44f8-a7a3-5bf6c2b54efa', 'CHINITO', 'CHINITO SUB.mp4', 'con basew en talones. gluteos activos. rodillas hacia afuera. junto escapulas. toda la planta del pie apoyada', null),
  ('6e6a6ea1-0bf1-4fcb-981d-aef6d7f92708', 'bicho muerto mano en rodilla contraria', 'Dead bug with isometric hand-to-knee press (opposite sides).MOV', 'mano en rodilla contraria, fuerzas opuestas  altas e iguales todo el tiempo. tomo aire arriba, mantengo al bajar brazo y pierna contraria  y suelto al subir, todas seguidas  a un lado luego al otro', null),
  ('483542b0-08cf-4b94-b7b4-36072cb9d369', 'SENTADILLA LATERAL CON DEFICIT', 'lateral squat.mp4', 'Pierna que NO esta en el step siempre extendida. rodillas hacia afuera. fuerza con espalda para mantenerla derecha.', null),
  ('f8698392-08dc-4814-b1d2-92d4e356e0be', 'carpa a spiderman', 'spiderman carpa.mp4', 'trato de hacer el movimiento lo mas fluido posible. en plancha busco llegar con talones al suelo y en spiderman rodilla de adelante hacia afuera y al subir el brazo abro bien el pecho', null),
  ('93e73280-eb44-447e-81ef-1d02a798d089', 'reloj en suelo', 'https://www.youtube.com/watch?v=0jL12X4qh6w', 'cabeza apoyada, brazos lo mas arriba posible todo el tiempo', null),
  ('341fad9d-fbc5-4acf-941e-8923bca2f8bb', 'ajuste en plancha', 'me sale para la bosta, no logro adelantar el pie ni acomodarlo. cuando lo llevo hacia adelante, no logro que quede a la altura de mis manos, salvo que me acomode, pero el movimiento no es natural', 'se junta y separa escapulas SIN que se caiga la cadera. core ajustado. tomo aire cuando rechazo y  mantengo al ajustar o juntar escapulas', null),
  ('a1d8a7c3-6018-48cd-bc22-78cfe3e5f9d7', 'STEP DOWN', 'step down.mp4', 'rodilla del cajon siempre hacia afuera y adelante. bajo hasta donde pueda controlar subida. evito arquearme mucho con espalda', null),
  ('7976ecf1-3259-4717-8ec7-dc8b41e4aef6', 'Dead Bug powerband', 'dead bug powerband.mp4', 'tomo aire arriba, mantengo al bajar y suelto al subir ajustando el abdomen. los pies buscan el suelo pero solo ROZAN con los talones el suelo, no se descarga el peso en ningun momento. avisar si hay dolor lumbar', null),
  ('6ebd1df9-7c6b-4210-a944-f28a9eee09a2', 'PLANCHA LATERAL JUNTO CODO CON RODILLA', 'lateral plank knee elbow.mp4', 'evito que cadera caiga. tomo aire mantengo al juntar y suelto al extender. cadera alineada.', null),
  ('f669b713-390e-46b5-afcb-6631e71c5208', 'GATO BUENO MALO', 'gato bueno malo.mp4', 'meto cola y cabeza subiendo columna al techo y luego al revez, mirada arriba saaco cola y panza al suelo.', null),
  ('7f940e39-e398-4087-90ca-805f259f7756', 'hombro con palo', 'SHOULDER MOBILITY OVER HAND .mp4', 'mientras mas angosto el agarre mas dificil. evitar arquear espalda o subir hombros. ajusto core llevando ombligo hacia la lumbar', null),
  ('62b437dd-8278-449a-9fe4-4514e0837e40', 'molino en chinito', 'molino chinit.mp4', 'ajusto gluteo,no "escondo" cola.  codos empujas rodilla afuera, roto lo mas posible, plantas del pie apoyadas en su totalidad', null),
  ('5e7c6567-7dcc-4a41-88d9-f1cac7e5e7df', 'PULL APART', 'PULL APART.mp4', 'PALMAS ARRIBA. mientras mas cerca el agarre mas dificil, codos siempre extendidos marco abduccion horizontal juntando escapulas atras. evitar levantar hombros o arquear espalda', null),
  ('07c98c81-5077-4f40-8c3b-da857881c1b6', 'patinadores', 'patinadores.mp4', 'mientras mas lejos la zancada, mas complejo para estabilizar. una vez que encuentro el equilibrio paso al otro lado, que no se vea como que te caes a los costados.', null),
  ('993f8d6c-59b0-48e5-a5c0-6dc08da2b661', 'pallof press isometrico polea', 'pallof press iso.mp4', 'mantengo posicion, codos extendidos completamente, aplico bracing, trato de no compensar con hombros (elevandolos) o con cadera (ladeandola)', null),
  ('4ac00928-05a0-4e0e-a82a-4be26ef07190', 'superman en plancha', 'superman plank(1).mp4', 'aplico bracing. tomo aire abajo mantengo al subir y suelto al bajar. mantener neutra la columna (no quebrar espalda baja). NO ABRIR CADERA.', null),
  ('90eb0d92-1c38-4b1b-8063-7f24a44daa8c', 'JEFFERSON', 'JEFFERSON.mp4', 'trato de bajar vertebra por vertebra, rodillas siempre extendidas , peso distribuido en TODA la planta del pie', null),
  ('e7c10ef6-ce0a-4c68-9f5e-0f11232234e2', 'PULL APART DIAGONAL', 'DIAGONAL PULL APART.mp4', 'Palma de abajo mira adelante. codos extendidos siempre. NO ARQUEO ESPALDA', null),
  ('9eeb917b-09dc-44f8-8d6f-8b9833a62332', 'movilidad de cadera con kb', 'https://www.youtube.com/shorts/ID4Dx8vPbUY', 'meto bien la cola todo el tiempo. voy lo mas abajo y adelante posible con la cadera', null),
  ('413f3663-96f6-4ed7-98b2-24721154f04c', 'SINGLE GLUTE RAISES + ABD', 'SINGLE GLUTE RAISES + ABD.mp4', 'CADERA ALINEADA SIEMPRE. cuando separo las rodillas mantengo estable la otra. al bajar no descargo peso', null),
  ('4b31e34e-4715-4b15-92f8-d55d9ffbc494', 'HALO SPLIT', 'HALO SPLIT EXP.mp4', 'RODILLA APOYADA. se trata de no mover el torso para no compensar el movimiento de brazos. movimiento completo y circular a la altura del cuello siempre. agarre pegado mas dificil que con manos mas separadas a la pesa rusa', null),
  ('847c5b07-4e63-4320-8199-134bafb23569', 'SALTO CAJON', 'box jump.mp4', 'CAJON A ALTURA POR DEBAJO DE RODILLAS. al salir: rodillas afuera. impulso con brazos desde atras. salto: busco completa extension y ALTURA para caer lo mas despacio y controlado posible sin hacer ruido. CAJON DE 30 CM IDEAL. sino 50', null),
  ('094e9c91-0b53-4112-a56f-c470c94acc8c', 'DYNAMIC PIGEON', 'DYNAMIC PIGEON.mp4', 'Bajo cadera lo mas posible. evito sentarme SOBRE la pierna adelantada.', null),
  ('34c559b9-f9a2-4699-9401-3a90bee6b51d', 'Sumo walk (diagonal)', 'sumo walk diagonal.mp4', 'trato de no destensar del todo la banda', null),
  ('0708d331-bc55-4915-b5c5-6e722eab25ba', '"goblet hold DEAD LIFT', 'DL TOMA CABRA SUB.mp4', 'marco bisagra de cadera. la cadera por atras de la linea de la rodilla y del pie. rodillas hacia afuera', null),
  ('90ccdb76-1440-49c6-8b14-fe2165153cc7', 'TEMPO SQ', 'TEMPO SQ(1).mp4', '3 seg para bajar. 2 seg mantengo y 1 seg para subir. aplico bracing.  rodillas hacia afuera y uso taco en talones.', null),
  ('5a3fe772-c626-448b-a19d-f36304101cff', 'Candelabro arrodillada', 'candelabro split position.mp4', 'evito arquear espalda en todo momento. palmas hacia abajo en todo momento. la idea es subir antebrazos y codos a la altura del hombro.', null),
  ('5c17507c-8a21-4ba7-b3b4-b3aa36fe802e', 'SEATED PANCAKE', 'seated pancake .mp4', 'rodillas extendidas, mas facil si se semiflexionan.  saco cola y pecho.', null),
  ('8f80b6e9-ce7f-4971-9157-f7819a33ae95', 'SPIDERMAN OPEN BOOK', 'open book spiderman .mp4', 'rodilla de atras bien extendida, junto escapulas  una vez que marco apertura con brazos', null),
  ('fc5932c8-4681-48e7-a954-0a58974a7a92', 'Rotacion toracica en sentadilla', '(294) Movilidad: Rotación torácica en sentadilla profunda. #movilidad #entrena #cadera #salud #sentadilla - YouTube', 'como en posicion de chinito, con un codo empujo rodilla hacia afuera con la otra,  roto lo mas posible abriendo pecho.', null),
  ('57edf997-ec8d-46b8-875e-1d837e725dbe', 'movilidad de tobillo', 'Movilidad de tobillo', 'busco una distancia justa en donde el talon no se levante y sientas q estas al limite.', null),
  ('99000848-1757-408e-a76b-86c78eeae27a', 'plancha trx', 'trx plank hand.mp4', 'pies flexionados.  empujo el suelo.  manos a altura del hombro.', null),
  ('02959437-c41f-4be8-8487-f3ce51d7001a', 'plancha lateral trx', '22- TRX plancha lateral', 'si es dificil puedo apoyar la mano en el suelo. trato q cadera no se ladee (que no se caiga para adelante o atras). solo mantengo posicion', null),
  ('4a9f93a7-bf0f-49a0-a0c2-e728b9743ecb', 'extension de cadera en polea', 'Extensión de cadera polea baja', 'no arqueo espalda. no ladear cadera. busco estabilizacion. la patada es cortita y la rodilla siempre extendida de la q tiene la polea', null),
  ('6631eb1b-f660-4201-aa40-c6dd80f60bf2', 'SQUAT TO HIP LIFT', 'https://www.youtube.com/shorts/VL3eQfMJoqs', 'de chinito a jefferson.', null),
  ('47097a5c-6ca4-4d4f-b5a3-0d9ec634563a', 'FROG HIP MOBILITY', 'https://www.youtube.com/shorts/aIC0zaSpXGc', 'llevo cadera hacia adelante y atras haciendo fuerza siempre hacia abajo buscando mas rango de movimiento', null),
  ('16f5af0d-7816-4b0d-9992-efd32458b2d4', 'SERRATO CON FITBALL', 'https://www.youtube.com/watch?v=j-AN84daEWI', 'PROBARLO SIN BANDA PRIMERO, SI ME SIENTO COMODO O SEGUNDO DIA PROBAR CON BANDA LIVIANA.', null),
  ('9e69e7c1-aa12-4e7b-a028-49c6c6a993d4', 'SHOULDER EXT/FLEX/AD.', 'shoulder flex-ext-ad .mp4', 'codos completamente extendidos. EVITO arquear espalda en todo momento.', null),
  ('d6d8f372-49be-4cbe-b96a-faeef48d2edb', 'ROLLER TRX', 'Roller TRX - YouTube', 'AJUSTO CORE. TOMO AIRE ARRIBA MANTENGO AL BAJAR Y SUELTO AL SUBIR. Mientras mas bajo mas dificil. no arquear espalda', null),
  ('cc414e71-91b4-418a-ba4a-a3da7f196aaa', 'PALLOF PRESS CON ROTACION', 'https://www.youtube.com/shorts/iAWKyMczcrs', 'ROTO AL LADO EXTERNO DE DONDE VIENE LA BANDA JUNTO CON CADERA AL MISMO TIEMPO Q LOS HOMBROS, CUANDO VUELVO, VUELVO AL CENTRO SIN ROTAR HACIA EL LADO DE DONDE VIENE LA BANDA. PRESTAR ATENCION A VIDEO', null),
  ('673098b0-087e-41cf-bbdd-14886d730241', 'hip extention wall', 'https://www.youtube.com/shorts/1deEC6s2XLc', 'todo pie apoyado en la pared. marco angulo de 90 grados. ajusto gluteo al subir y controlo la cadera que no se ladee.', null),
  ('1d4b7cc9-f5a9-43b9-b6d6-4c4b8f77ecb5', 'MOVILIDAD TORACICA', 'https://www.youtube.com/shorts/VfqwqWY9wTs', 'PECHO FUERA HACIA ABAJO, PANZA HACIA ARRIBA, NO ARQUEO ESPALDA.', null),
